import{_ as e,a as o,b as a,c as d,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as i}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as c,o as s,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Other/ocr.md","filePath":"fa/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"fa/Other/ocr.md"};function u(h,t,g,m,b,y){return s(),n("div",null,[...t[0]||(t[0]=[l('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR متن را از images، scans و document screenshots استخراج می‌کند.</p><p>پس از recognition، می‌توانید result را copy کنید، به‌صورت <code>Markdown</code>، <code>PDF</code> یا <code>Word</code> export کنید، یا چند format را با هم package و download کنید.</p><h2 id="ocr-چه-کارهایی-می‌تواند-انجام-دهد" tabindex="-1">OCR چه کارهایی می‌تواند انجام دهد <a class="header-anchor" href="#ocr-چه-کارهایی-می‌تواند-انجام-دهد" aria-label="Permalink to &quot;OCR چه کارهایی می‌تواند انجام دهد&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Image text recognition</td><td>استخراج text از images، screenshots و scans.</td></tr><tr><td>Document layout recognition</td><td>مناسب‌تر برای tables، formulas، stamps و mixed text-image layouts.</td></tr><tr><td>Multiple services</td><td>پشتیبانی از Baidu PaddleOCR، Microsoft Azure Vision و Google Vision.</td></tr><tr><td>Copy results</td><td>copy کردن recognized text پس از processing.</td></tr><tr><td>Export files</td><td>export کردن <code>Markdown</code>، <code>PDF</code> و <code>Word</code>.</td></tr><tr><td>Batch packaging</td><td>پس از recognize کردن چند file، results را به‌صورت package download کنید.</td></tr></tbody></table><h2 id="ابتدا-ocr-services-را-configure-کنید" tabindex="-1">ابتدا OCR Services را Configure کنید <a class="header-anchor" href="#ابتدا-ocr-services-را-configure-کنید" aria-label="Permalink to &quot;ابتدا OCR Services را Configure کنید&quot;">​</a></h2><p>باز کنید:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+e+'" alt="IP geolocation and OCR" loading="lazy"></p><p>credentials مربوط به services موردنیاز را وارد کنید:</p><table tabindex="0"><thead><tr><th>Service</th><th>What To Enter</th><th>Best For</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>انتخاب پیشنهادی اول. مناسب documents، images، tables و mixed layouts.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> و <code>Azure Vision API Key</code></td><td>اگر از Microsoft cloud services استفاده می‌کنید مفید است.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. Service account <code>JSON</code> فقط برای quota query استفاده می‌شود.</td><td>اگر از Google Cloud services استفاده می‌کنید مفید است.</td></tr></tbody></table><p>بعد از پر کردن credentials، save کنید.</p><p>برای تست اولیه، configure کردن یک service کافی است. لازم نیست هر سه را داشته باشید.</p><h2 id="google-vision-setup" tabindex="-1">Google Vision Setup <a class="header-anchor" href="#google-vision-setup" aria-label="Permalink to &quot;Google Vision Setup&quot;">​</a></h2><p>Google setup دو بخش دارد:</p><table tabindex="0"><thead><tr><th>Goal</th><th>Requirement</th></tr></thead><tbody><tr><td>استفاده از OCR</td><td><code>Cloud Vision API</code> را enable کنید و سپس <code>API Key</code> بسازید.</td></tr><tr><td>query کردن usage</td><td>service account بسازید، <code>Monitoring Viewer</code> بدهید، سپس service account <code>JSON</code> را download کنید.</td></tr></tbody></table><p><img src="'+i+'" alt="Google API key and service account" loading="lazy"></p><h3 id="استفاده-از-google-برای-ocr" tabindex="-1">استفاده از Google برای OCR <a class="header-anchor" href="#استفاده-از-google-برای-ocr" aria-label="Permalink to &quot;استفاده از Google برای OCR&quot;">​</a></h3><ol><li>Google Cloud Console را باز کنید.</li><li>به <code>APIs &amp; Services</code> بروید.</li><li><code>Library</code> را باز کنید، <code>Cloud Vision API</code> را جست‌وجو و enable کنید.</li><li>به <code>Credentials</code> برگردید.</li><li><code>API Key</code> بسازید.</li><li>API Key را باز و copy کنید.</li><li>در ImgBed داخل <code>Google Vision API Key</code> paste کنید.</li><li>Save کنید.</li></ol><p>بعد از آن می‌توانید Google Vision را در OCR dialog انتخاب کنید.</p><h3 id="query-کردن-google-usage" tabindex="-1">Query کردن Google Usage <a class="header-anchor" href="#query-کردن-google-usage" aria-label="Permalink to &quot;Query کردن Google Usage&quot;">​</a></h3><p>Quota query برای recognition لازم نیست.</p><p>فقط حدوداً نشان می‌دهد در 30 روز گذشته چند Google Vision call استفاده شده است.</p><ol><li>در Google Cloud Console، <code>IAM &amp; Admin</code> را باز کنید.</li><li><code>Service Accounts</code> را باز کنید.</li><li>service account بسازید، مثل <code>vision-monitor</code>.</li><li>role <code>Monitoring Viewer</code> را به آن بدهید.</li><li>جزئیات service account را باز کنید و key بسازید.</li><li><code>JSON</code> را انتخاب کنید.</li><li>generated JSON file را download کنید.</li><li>به ImgBed برگردید و آن را زیر service account <code>JSON</code> import کنید (اختیاری).</li><li>پس از موفقیت import، quota query را بزنید.</li></ol><p>پس از import، ImgBed نام project مالک service account را نشان می‌دهد. هنگام query usage، ImgBed Google monitoring data را می‌خواند و call count این ماه را نشان می‌دهد.</p><p>خلاصه:</p><table tabindex="0"><thead><tr><th>Item</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>OCR recognition را اجرا می‌کند.</td></tr><tr><td>Service account <code>JSON</code></td><td>تعداد Google Vision calls استفاده‌شده را query می‌کند.</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>اجازه می‌دهد service account usage data را بخواند.</td></tr></tbody></table><h2 id="گرفتن-baidu-paddleocr-token" tabindex="-1">گرفتن Baidu PaddleOCR Token <a class="header-anchor" href="#گرفتن-baidu-paddleocr-token" aria-label="Permalink to &quot;گرفتن Baidu PaddleOCR Token&quot;">​</a></h2><p>Baidu PaddleOCR به access token نیاز دارد.</p><p><img src="'+o+'" alt="Get PaddleOCR token" loading="lazy"></p><p>در صفحه Baidu PaddleOCR، پنجره <code>API</code> call را باز کنید، برای گرفتن token کلیک کنید و آن را copy کنید.</p><p>به ImgBed برگردید، داخل <code>PaddleOCR Token</code> paste کنید و save کنید.</p><h2 id="شروع-recognition" tabindex="-1">شروع Recognition <a class="header-anchor" href="#شروع-recognition" aria-label="Permalink to &quot;شروع Recognition&quot;">​</a></h2><p>در File Management، یک image یا document screenshot انتخاب کنید و <code>OCR</code> را بزنید.</p><p><img src="'+a+'" alt="OCR recognition" loading="lazy"></p><p>در dialog، recognition service و model را انتخاب کنید.</p><p>مدل‌های رایج PaddleOCR:</p><table tabindex="0"><thead><tr><th>Model</th><th>Best For</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>default پیشنهادی. مناسب documents، tables، formulas، stamps و mixed layouts.</td></tr><tr><td><code>PP-OCRv5</code></td><td>simple images، ordinary text و lightweight recognition.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>multilingual، complex images و chart-like content.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>document pages پیچیده‌تر و layout recovery.</td></tr></tbody></table><p>اگر مطمئن نیستید، با <code>PP-StructureV3</code> شروع کنید.</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Orientation correction</td><td>وقتی image چرخیده یا skewed است.</td></tr><tr><td>Document flattening</td><td>برای photographed documents با curvature یا tilt.</td></tr><tr><td>Layout detection</td><td>وقتی می‌خواهید headings، paragraphs، tables و image structure حفظ شود.</td></tr><tr><td>Chart recognition</td><td>وقتی image شامل charts یا structures پیچیده است.</td></tr><tr><td>Beautify <code>Markdown</code></td><td>exported Markdown را خواناتر می‌کند.</td></tr></tbody></table><p>برای screenshots عادی، options را حداقلی نگه دارید. برای document scans، گزینه‌های مرتبط با document را بیشتر enable کنید.</p><h2 id="مشاهده-results" tabindex="-1">مشاهده Results <a class="header-anchor" href="#مشاهده-results" aria-label="Permalink to &quot;مشاهده Results&quot;">​</a></h2><p>پس از پایان recognition، dialog result را نشان می‌دهد.</p><p>می‌توانید آن را مستقیم copy کنید یا export formats را انتخاب کنید.</p><p><img src="'+d+'" alt="PDF recognition" loading="lazy"></p><p>برای document pages، exported <code>PDF</code> می‌تواند ظاهر page را حفظ کند و text را searchable نگه دارد. برای archive کردن scans و پیدا کردن content بعداً مفید است.</p><h2 id="انتخاب-export-format" tabindex="-1">انتخاب Export Format <a class="header-anchor" href="#انتخاب-export-format" aria-label="Permalink to &quot;انتخاب Export Format&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Best For</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>notes، documentation systems و later editing.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>حفظ ظاهر page و scanned document results.</td></tr><tr><td><code>Word (.docx)</code></td><td>ادامه layout editing، text modification و handoff به دیگران.</td></tr><tr><td>Export all</td><td>ذخیره multiple formats و original image، مناسب archives مهم.</td></tr></tbody></table><p>اگر فقط text می‌خواهید، Markdown export کنید.</p><p>اگر ظاهر page مهم است، PDF یا Word استفاده کنید.</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>exported Word documents با office software قابل باز کردن و edit هستند.</p><p><img src="'+r+`" alt="Word result" loading="lazy"></p><p>بعضی documents شامل recognized images، headings و paragraphs در Word output هستند.</p><p>recognition quality به original image clarity، model choice و document complexity بستگی دارد.</p><h2 id="بهترین-file-types-برای-ocr" tabindex="-1">بهترین File Types برای OCR <a class="header-anchor" href="#بهترین-file-types-برای-ocr" aria-label="Permalink to &quot;بهترین File Types برای OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File Type</th><th>Recommendation</th></tr></thead><tbody><tr><td>Clear screenshots</td><td>مستقیم recognize کنید.</td></tr><tr><td>Scans</td><td><code>PP-StructureV3</code> را ترجیح دهید.</td></tr><tr><td>Photographed documents</td><td>orientation correction و document flattening را enable کنید.</td></tr><tr><td>Tables, formulas, stamps</td><td>structured models را ترجیح دهید.</td></tr><tr><td>Simple short text images</td><td><code>PP-OCRv5</code> معمولاً کافی است.</td></tr></tbody></table><p>images واضح‌تر با text صاف‌تر معمولاً result بهتری می‌دهند.</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Recognition fails</td><td>بررسی کنید service token یا key ذخیره شده باشد.</td></tr><tr><td>Recognition slow است</td><td>documents پیچیده و images بزرگ زمان بیشتری می‌برند.</td></tr><tr><td>Table incomplete است</td><td>یک structured model امتحان کنید.</td></tr><tr><td>Text mistakes دارد</td><td>blur، glare و skew خطا را زیاد می‌کنند. image واضح‌تر امتحان کنید.</td></tr><tr><td>Word output images زیادی دارد</td><td>structured models ممکن است بعضی recognized images را حفظ کنند. این عادی است.</td></tr></tbody></table><h3 id="google-quota-query-fail-می‌شود" tabindex="-1">Google Quota Query Fail می‌شود <a class="header-anchor" href="#google-quota-query-fail-می‌شود" aria-label="Permalink to &quot;Google Quota Query Fail می‌شود&quot;">​</a></h3><p>بررسی کنید:</p><ol><li>Service account <code>JSON</code> import شده باشد.</li><li>service account role <code>Monitoring Viewer</code> داشته باشد.</li><li><code>Cloud Vision API</code> برای project enabled باشد.</li></ol><p>اگر فقط OCR لازم دارید و usage query نمی‌خواهید، می‌توانید service account JSON را نادیده بگیرید و فقط <code>Google Vision API Key</code> را وارد کنید.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings را باز کنید</span></span>
<span class="line"><span>-&gt; Other Settings را باز کنید</span></span>
<span class="line"><span>-&gt; OCR service credentials را وارد کنید</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; به File Management برگردید</span></span>
<span class="line"><span>-&gt; file را انتخاب کنید و OCR را بزنید</span></span>
<span class="line"><span>-&gt; model را انتخاب کنید</span></span>
<span class="line"><span>-&gt; منتظر recognition بمانید</span></span>
<span class="line"><span>-&gt; results را copy کنید یا Markdown / PDF / Word export کنید</span></span></code></pre></div>`,67)])])}const v=c(p,[["render",u]]);export{C as __pageData,v as default};
